+  const session = await fetch('https://api.stripe.com/v1/checkout/sessions', {
+    headers: { Authorization: `Bearer ${STRIPE_SECRET}` },
+    method: 'POST',
+    body: JSON.stringify({ line_items: items.map(i => ({ ...i })) }),
+  });
